export function divideCardsForSliders(datas) {
    const firstCardsNine = datas.slice(0, 10);
    const secondCardsNine = datas.slice(10, 20);
    const thirdCardsNine = datas.slice(20, 30);
    const existingCards = datas.slice(30);
  
    return {
      firstCardsNine,
      secondCardsNine,
      thirdCardsNine,
      existingCards
    };
  }
  
  export function getSliderSettings(firstCardsNine, secondCardsNine, thirdCardsNine, existingCards) {
    const firstCardsNineSettings = { infinite: false, slidesToShow: Math.min(firstCardsNine.length, 10) };
    const secondCardsNineSettings = { infinite: false, slidesToShow: Math.min(secondCardsNine.length, 10) };
    const thirdCardsNineSettings = { infinite: false, slidesToShow: Math.min(thirdCardsNine.length, 10) };
    const existingCardsSettings = { infinite: true, slidesToShow: Math.min(existingCards.length, 10), autoplay: true, autoplaySpeed: 2000 };
  
    return {
      firstCardsNineSettings,
      secondCardsNineSettings,
      thirdCardsNineSettings,
      existingCardsSettings
    };
  }
  